  it("github-copilot", () => {
    const agent = getAgent("github-copilot");
    assert.equal(
      resolveAgentSkillPathFor(agent, SKILL, HOME, p),
      path.join(HOME, ".copilot", "skills", SKILL),
    );
  });
});

