const { execFileSync } = require("child_process");
const { readFileSync } = require("fs");

function lookupHomeForUserWith(username, platform, execFileFn, readFileFn) {
  console.log(`Looking up home for user: ${username} on platform: ${platform}`);

  // Try getent on non-darwin
  if (platform !== "darwin") {
    console.log("Trying getent (non-darwin)...");
    try {
      const out = execFileFn("getent", ["passwd", username], {
        encoding: "utf8",
        stdio: ["ignore", "pipe", "ignore"],
      }).trim();
      const home = out.split(":")[5];
      console.log(`getent succeeded: ${home}`);
      if (typeof home === "string" && home.startsWith("/")) return home;
    } catch (e) {
      console.log(`getent failed: ${e.message}`);
    }
  }

  // Try dscl on darwin
  if (platform === "darwin") {
    console.log("Trying dscl (darwin)...");
    try {
      const out = execFileSync(
        "dscl",
        [".", "-read", `/Users/${username}`, "NFSHomeDirectory"],
        { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] },
      ).trim();
      const home = out.replace(/^NFSHomeDirectory:\s*/, "").trim();
      console.log(`dscl succeeded: ${home}`);
      if (home.startsWith("/")) return home;
    } catch (e) {
      console.log(`dscl failed: ${e.message}`);
    }
  }

  // Try /etc/passwd
  console.log("Trying /etc/passwd...");
  try {
    const passwd = readFileSync("/etc/passwd", "utf8");
    for (const line of passwd.split("\n")) {
      const parts = line.split(":");
      if (parts[0] === username) {
        const home = parts[5];
        console.log(`Found in /etc/passwd: ${home}`);
        if (typeof home === "string" && home.startsWith("/")) return home;
      }
    }
    console.log(`User ${username} not found in /etc/passwd`);
  } catch (e) {
    console.log(`/etc/passwd failed: ${e.message}`);
  }

  throw new Error(`Cannot determine home directory for user "${username}"`);
}

